/**
 * 시현이 놀이터 OS — 긴급출동! 초강력 소방대 V8 (Ultimate Master Edition)
 * 업데이트: V7 피드백 완벽 반영 (반응형 간격, 모바일 파티클 최적화, 상태 초기화 픽스)
 */

(function () {
  const GAME_KEY = 'megaDispatchV8';
  const STYLE_ID = 'sihyeon-mega-v8-style';
  const FIRE_DATA = './assets/vehicles/fire_manifest.json'; 

  const state = {
    container: null,
    options: {},
    allTrucks: [],
    mission: [],
    currentLevel: 1, 
    userIndex: 0,
    combo: 0,
    isBusy: false,
    destroyed: false
  };

  const ROLE_ICONS = {
    pump_engine: '💧', water_tanker: '💧', airport_crash_tender: '💧', foam_tender: '💧',
    ladder_truck: '🪜', aerial_ladder_truck: '🪜', articulating_ladder_truck: '🪜',
    rescue_fire_truck: '⛑️', fire_command_car: '📢'
  };

  function injectStyle() {
    if (document.getElementById(STYLE_ID)) return;
    const s = document.createElement('style');
    s.id = STYLE_ID;
    s.textContent = `
      .md8-root {
        width: 100%; height: 100%; display: flex; flex-direction: column;
        background: #050505; position: relative; overflow: hidden;
        font-family: 'Jua', sans-serif;
      }
      
      .md8-city-bg {
        position: absolute; inset: 0; background: linear-gradient(rgba(0,0,0,0.4), rgba(0,0,0,0.4)), url('./assets/games/dispatch/city_night.webp') center bottom / cover;
        opacity: 0.7; z-index: 1; pointer-events: none;
      }

      /* [수정] 배경 불 효과 & 애니메이션 */
      .md8-fire-overlay {
        position: absolute; bottom: 0; left: 0; width: 100%; height: 45%;
        background: linear-gradient(transparent, rgba(255, 80, 0, 0.25));
        z-index: 2; pointer-events: none; animation: subtleFire 3s infinite alternate;
      }
      @keyframes subtleFire { from { opacity: 0.25; } to { opacity: 0.55; } }

      /* [수정] 헤더: clamp를 이용한 반응형 간격 처리 */
      .md8-header { 
        position: relative; z-index: 10; min-height: 140px;
        background: rgba(0,0,0,0.8); display: flex; align-items: center; justify-content: center; 
        gap: clamp(12px, 3vw, 28px); border-bottom: 6px solid #ff1744; padding: 10px;
      }

      /* [수정] 미션 카드 & 이미지 최적화 */
      .md-mission-card {
        width: clamp(70px, 15vw, 100px); height: clamp(70px, 15vw, 100px);
        background: #fff; border-radius: 22px; display: flex; align-items: center; justify-content: center;
        border: 5px solid #fff; position: relative; transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      }
      .md-mission-card img { width: 82%; height: 82%; object-fit: contain; }
      .md-mission-card.active { border-color: #ffeb3b; transform: scale(1.25) rotate(5deg); box-shadow: 0 0 30px #ffeb3b; }
      .md-mission-card.done { opacity: 0.25; filter: grayscale(100%); transform: scale(0.8); }

      .md-role-tag { font-size: 16px; position: absolute; top: -12px; right: -12px; background: #fff; border-radius: 50%; width: 30px; height: 30px; display: grid; place-items: center; box-shadow: 0 2px 5px rgba(0,0,0,0.3); z-index:5; }

      .md8-level-badge { position: absolute; top: 15px; left: 20px; background: #ff1744; color: #fff; padding: 5px 15px; border-radius: 15px; font-size: clamp(18px, 4vw, 24px); font-weight: 900; z-index: 100; border: 3px solid #fff; }

      .md8-garage { flex: 1; display: grid; grid-template-columns: repeat(3, 1fr); gap: 15px; padding: 20px; z-index: 10; align-content: center; }
      .md8-truck-btn { aspect-ratio: 1/1; background: #fff; border-radius: 25px; border: none; box-shadow: 0 10px 0 #888; display: flex; align-items: center; justify-content: center; position: relative; transition: transform 0.1s; overflow: visible; }
      .md8-truck-btn img { width: 95%; height: 95%; object-fit: contain; }
      
      .md8-spotlight { position: absolute; inset: -10%; background: radial-gradient(circle, rgba(255,255,255,0.5) 0%, transparent 70%); opacity: 0; transition: opacity 0.2s; pointer-events: none; }
      .md8-truck-btn.touch-active .md8-spotlight { opacity: 1; }
      .md8-truck-btn.touch-active { transform: translateY(8px); box-shadow: 0 2px 0 #888; }

      /* [복구] 쉐이크 애니메이션 */
      .md-shake { animation: mdShake 0.45s linear; }
      @keyframes mdShake {
        0%, 100% { transform: translateX(0); }
        10%, 30%, 50%, 70%, 90% { transform: translateX(-8px); }
        20%, 40%, 60%, 80% { transform: translateX(8px); }
      }

      /* [수정] 엔딩 화면 버튼 최적화 */
      #restartBtn { min-width: 220px; margin-top: 20px; padding: 15px 40px; font-size: 24px; border-radius: 30px; background: #ff1744; color: #fff; border: none; box-shadow: 0 8px 0 #b71c1c; font-weight: 900; }

      .water-drop { position: absolute; width: 14px; height: 14px; background: #4fc3f7; border-radius: 50%; pointer-events: none; z-index: 1000; animation: waterFly 0.7s ease-out forwards; }
      @keyframes waterFly { to { transform: translate(var(--tx), var(--ty)) scale(0); opacity: 0; } }

      @media (min-width: 768px) {
        .md8-garage { gap: 30px; padding: 40px; max-width: 900px; margin: 0 auto; }
        .md8-header { min-height: 180px; gap: 30px; }
      }
    `;
    document.head.appendChild(s);
  }

  /* [수정] 모바일 파티클 최적화 */
  function shootWater(x, y, isSuper = false) {
    const isMobile = window.innerWidth < 768;
    const count = isSuper ? (isMobile ? 22 : 35) : (isMobile ? 12 : 18);
    for (let i = 0; i < count; i++) {
      const drop = document.createElement('div');
      drop.className = 'water-drop';
      drop.style.left = x + 'px'; drop.style.top = y + 'px';
      drop.style.setProperty('--tx', (Math.random() * (isSuper ? 400 : 200) - (isSuper ? 200 : 100)) + 'px');
      drop.style.setProperty('--ty', (Math.random() * -300 - 50) + 'px');
      state.container.appendChild(drop);
      setTimeout(() => drop.remove(), 700);
    }
  }

  async function startRound() {
    if (state.destroyed) return;
    
    // [수정] 안전한 상태 초기화
    state.isBusy = false;
    state.userIndex = 0;

    if (state.allTrucks.length === 0) {
      const res = await fetch(FIRE_DATA); 
      state.allTrucks = await res.json();
    }
    const missionCount = Math.min(state.currentLevel + 1, 5);
    state.mission = [...state.allTrucks].sort(() => 0.5 - Math.random()).slice(0, missionCount);
    
    render();

    // [복구] 시작 음성 가이드
    if (state.options.speakGuide) {
      state.options.speakGuide(`레벨 ${state.currentLevel}! 순서대로 출동하자!`, true);
    }
  }

  function render() {
    if (state.destroyed || !state.container) return;
    state.container.innerHTML = `
      <div class="md8-root">
        <div class="md8-city-bg"></div>
        <div class="md8-fire-overlay"></div>
        <div class="md8-level-badge">LEVEL ${state.currentLevel}</div>
        <div class="md8-header">
          ${state.mission.map((m, i) => `
            <div class="md-mission-card ${i === state.userIndex ? 'active' : (i < state.userIndex ? 'done' : '')}">
              <div class="md-role-tag">${ROLE_ICONS[m.id] || '🚒'}</div>
              <img src="${m.file}">
            </div>
          `).join(' <span style="color:#fff; font-size:24px;">▶</span> ')}
        </div>
        <div class="md8-garage">
          ${state.allTrucks.slice(0, 9).map(t => `
            <button class="md8-truck-btn" data-id="${t.id}">
              <div class="md8-spotlight"></div>
              <img src="${t.file}">
            </button>
          `).join('')}
        </div>
      </div>
    `;
    state.container.querySelectorAll('.md8-truck-btn').forEach(btn => {
      btn.onclick = (e) => handleTouch(btn.dataset.id, btn, e);
    });
  }

  function handleTouch(id, el, e) {
    if (state.isBusy || state.destroyed) return;

    el.classList.add('touch-active');
    setTimeout(() => el.classList.remove('touch-active'), 280);

    const target = state.mission[state.userIndex];

    if (id === target.id) {
      state.userIndex++;
      state.combo++;
      const isSuper = state.combo >= 2; // [수정] 4살 추천 밸런스
      shootWater(e.clientX, e.clientY, isSuper);
      if (navigator.vibrate) navigator.vibrate(isSuper ? 150 : 80);

      const msg = isSuper ? "초강력!! " : "";
      if (state.options.speakGuide) {
        state.options.speakGuide(`${msg}${target.name_ko} 출동! ${target.sound_ko || ''}`, true);
      }
      
      if (state.userIndex >= state.mission.length) {
        state.isBusy = true;
        setTimeout(finishRound, 700);
      } else {
        setTimeout(render, 550);
      }
    } else {
      state.combo = 0;
      if (state.options.speakGuide) state.options.speakGuide("아니야! 다시 봐보자!", true);
      if (navigator.vibrate) navigator.vibrate([40, 60, 40]);
      
      const root = state.container.querySelector('.md8-root');
      if (root) {
        root.classList.add('md-shake');
        setTimeout(() => root.classList.remove('md-shake'), 450);
      }
    }
  }

  /* [수정] 명시적 상태 관리 및 애니메이션 최적화 */
  function finishRound() {
    if (state.destroyed) return;
    
    state.combo = 0;
    state.isBusy = true; 
    
    if (state.options.fireConfetti) state.options.fireConfetti();
    if (state.options.gainExp) state.options.gainExp(25 + state.currentLevel * 18);

    const clearedLevel = state.currentLevel;

    if (clearedLevel === 8) {
        showEnding();
        return;
    }

    state.currentLevel++;
    if (state.options.speakGuide) {
      state.options.speakGuide(`와아아! ${clearedLevel}레벨 클리어!! 다음 레벨 출동!`, true);
    }

    const trucks = state.container.querySelectorAll('.md8-truck-btn');
    trucks.forEach((btn, i) => {
      setTimeout(() => {
        btn.style.transition = '1.05s cubic-bezier(0.55, 0, 1, 1)';
        btn.style.transform = 'translateX(200vw) scale(1.55) rotate(22deg)';
      }, i * 70);
    });

    setTimeout(startRound, 2750);
  }

  /* [수정] 엔딩 후 재시작 로직 강화 */
  function showEnding() {
    state.isBusy = true;
    state.combo = 0;
    state.container.innerHTML = `
      <div class="md8-root" style="justify-content:center; align-items:center; text-align:center; color:#fff;">
        <div class="md8-city-bg"></div>
        <div style="z-index:100;">
          <h1 style="font-size: clamp(32px, 8vw, 52px); color: gold; text-shadow:0 0 30px red;">🏆 전설의 시현 본부장 🏆</h1>
          <p style="font-size: clamp(18px, 4vw, 26px);">시현이가 모든 불을 다 껐어요!</p>
          <div style="font-size: 80px; margin: 20px 0;">🚒🔥🚑🚓</div>
          <button id="restartBtn">다시 출동! 🔄</button>
        </div>
      </div>
    `;
    if (state.options.speakGuide) state.options.speakGuide("시현 본부장님 만세! 당신은 최고의 소방 영웅입니다!", true);
    
    document.getElementById('restartBtn').onclick = () => { 
      state.currentLevel = 1; 
      state.combo = 0;
      state.isBusy = false;
      startRound(); 
    };
  }

  function destroy() {
    state.destroyed = true;
    if (state.container) state.container.innerHTML = '';
    state.container = null;
  }

  window.SihyeonGames = window.SihyeonGames || {};
  window.SihyeonGames[GAME_KEY] = { 
    render: (c, o) => { state.container=c; state.options=o; state.destroyed=false; injectStyle(); startRound(); }, 
    destroy 
  };
})();
